[asy]
pair pA, pB, pC, pO;
pO = (0, 0);
pA = pO + dir(-40);
pB = pO + dir(100);
pC = pO + dir(180);
draw(pA--pC--pB);
label("$A$", pA, SE);
label("$B$", pB, N);
label("$C$", pC, W);
draw(circle(pO, 1));
[/asy]

